from dataclasses import dataclass
from typing import List, Dict

@dataclass
class CacheConfiguration:
    atomicity_mode: str
    cache_mode: str
    write_synchronization_mode: str

@dataclass
class IgniteConfiguration:
    cache_configuration: List[CacheConfiguration]

def configure_cache() -> IgniteConfiguration:
    cache_config = CacheConfiguration(
        atomicity_mode='ATOMIC',
        cache_mode='PARTITIONED',
        write_synchronization_mode='FULL_SYNC'
    )
    return IgniteConfiguration(cache_configuration=[cache_config])

def main() -> None:
    ignite_config = configure_cache()
    for cache in ignite_config.cache_configuration:
        print(f"Cache Mode: {cache.cache_mode}, Atomicity Mode: {cache.atomicity_mode}, Write Sync Mode: {cache.write_synchronization_mode}")

if __name__ == "__main__":
    main()
